def is_prime(n):
    """Check if a positive integer n is prime."""
    if n <= 1:
        return False
    # Check divisibility from 2 up to the square root of n
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def is_prime_length(string):
    """Returns True if the length of the string is a prime number, otherwise False."""
    length = len(string)
    return is_prime(length)

# Examples
print(f"Is 'Hello' length prime? {is_prime_length('Hello')}")    # True: length is 5
print(f"Is 'abcdcba' length prime? {is_prime_length('abcdcba')}")  # True: length is 7
print(f"Is 'kittens' length prime? {is_prime_length('kittens')}")   # True: length is 7
print(f"Is 'orange' length prime? {is_prime_length('orange')}")    # False: length is 6
```
